  1	import React, { FC, useMemo, useState } from 'react';
  2	import { Link } from 'react-router-dom-v5-compat';
  3	import produce from 'immer';
  4	
  5	import { IoK8sApiCoreV1Node } from '@kubevirt-ui/kubevirt-api/kubernetes';
  6	import { V1VirtualMachine, V1VirtualMachineInstance } from '@kubevirt-ui/kubevirt-api/kubevirt';
  7	import Loading from '@kubevirt-utils/components/Loading/Loading';
  8	import ModalPendingChangesAlert from '@kubevirt-utils/components/PendingChanges/ModalPendingChangesAlert/ModalPendingChangesAlert';
  9	import TabModal from '@kubevirt-utils/components/TabModal/TabModal';
 10	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 11	import { modelToGroupVersionKind, NodeModel } from '@kubevirt-utils/models';
 12	import { getCPU } from '@kubevirt-utils/resources/vm';
 13	import { ensurePath } from '@kubevirt-utils/utils/utils';
 14	import { isEmpty } from '@kubevirt-utils/utils/utils';
 15	import { ResourceLink, useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 16	import {
 17	  Alert,
 18	  AlertVariant,
 19	  Button,
 20	  Checkbox,
 21	  Form,
 22	  FormGroup,
 23	  Label,
 24	  Popover,
 25	} from '@patternfly/react-core';
 26	
 27	import { cpuManagerLabel, cpuManagerLabelKey, cpuManagerLabelValue } from './utils/constants';
 28	
 29	type DedicatedResourcesModalProps = {
 30	  headerText: string;
 31	  isOpen: boolean;
 32	  onClose: () => void;
 33	  onSubmit: (updatedVM: V1VirtualMachine) => Promise<V1VirtualMachine | void>;
 34	  vm: V1VirtualMachine;
 35	  vmi?: V1VirtualMachineInstance;
 36	};
 37	
 38	const DedicatedResourcesModal: FC<DedicatedResourcesModalProps> = ({
 39	  headerText,
 40	  isOpen,
 41	  onClose,
 42	  onSubmit,
 43	  vm,
 44	  vmi,
 45	}) => {
 46	  const { t } = useKubevirtTranslation();
 47	  const [checked, setChecked] = useState<boolean>(!!getCPU(vm)?.dedicatedCpuPlacement);
 48	
 49	  const [nodes, loaded, loadError] = useK8sWatchResource<IoK8sApiCoreV1Node[]>({
 50	    groupVersionKind: modelToGroupVersionKind(NodeModel),
 51	    isList: true,
 52	  });
 53	
 54	  const { hasNodes, qualifiedNodes } = useMemo(() => {
 55	    const filteredNodes = nodes?.filter(
 56	      (node) => node?.metadata?.labels?.[cpuManagerLabelKey] === cpuManagerLabelValue,
 57	    );
 58	    return {
 59	      hasNodes: !!filteredNodes?.length,
 60	      qualifiedNodes: filteredNodes,
 61	    };
 62	  }, [nodes]);
 63	
 64	  const updatedVirtualMachine = useMemo(() => {
 65	    const updatedVM = produce<V1VirtualMachine>(vm, (vmDraft: V1VirtualMachine) => {
 66	      ensurePath(vmDraft, ['spec.template.spec.domain.cpu']);
 67	      vmDraft.spec.template.spec.domain.cpu.dedicatedCpuPlacement = checked;
 68	    });
 69	    return updatedVM;
 70	  }, [vm, checked]);
 71	  return (
 72	    <TabModal
 73	      headerText={headerText}
 74	      isOpen={isOpen}
 75	      obj={updatedVirtualMachine}
 76	      onClose={onClose}
 77	      onSubmit={onSubmit}
 78	    >
 79	      <Form>
 80	        {vmi && <ModalPendingChangesAlert />}
 81	        <FormGroup fieldId="dedicated-resources" isInline>
 82	          <Checkbox
 83	            description={
 84	              <>
 85	                {t('Available only on Nodes with labels')}{' '}
 86	                <Label color="purple" variant="filled">
 87	                  {!isEmpty(nodes) ? (
 88	                    <Link
 89	                      target="_blank"
 90	                      to={`/search?kind=${NodeModel.kind}&q=${encodeURIComponent(cpuManagerLabel)}`}
 91	                    >
 92	                      {cpuManagerLabel}
 93	                    </Link>
 94	                  ) : (
 95	                    cpuManagerLabel
 96	                  )}
 97	                </Label>
 98	              </>
 99	            }
100	            id="dedicated-resources"
101	            isChecked={checked}
102	            label={t('Schedule this workload with dedicated resources (guaranteed policy)')}
103	            onChange={(_event, val) => setChecked(val)}
104	          />
105	        </FormGroup>
106	        <FormGroup fieldId="dedicated-resources-node">
107	          {!isEmpty(nodes) ? (
108	            <Alert
109	              title={
110	                hasNodes
111	                  ? t('{{qualifiedNodesCount}} matching nodes found', {
112	                      qualifiedNodesCount: qualifiedNodes?.length,
113	                    })
114	                  : t('No matching nodes found for the {{cpuManagerLabel}} label', {
115	                      cpuManagerLabel,
116	                    })
117	              }
118	              isInline
119	              variant={hasNodes ? AlertVariant.success : AlertVariant.warning}
120	            >
121	              {hasNodes ? (
122	                <Popover
123	                  bodyContent={
124	                    <>
125	                      {qualifiedNodes?.map((node) => (
126	                        <ResourceLink
127	                          groupVersionKind={modelToGroupVersionKind(NodeModel)}
128	                          key={node.metadata.uid}
129	                          name={node.metadata.name}
130	                        />
131	                      ))}
132	                    </>
133	                  }
134	                  headerContent={t('{{qualifiedNodesCount}} nodes found', {
135	                    qualifiedNodesCount: qualifiedNodes?.length,
136	                  })}
137	                >
138	                  <Button isInline onClick={() => setChecked(false)} variant="link">
139	                    {t('view {{qualifiedNodesCount}} matching nodes', {
140	                      qualifiedNodesCount: qualifiedNodes?.length,
141	                    })}
142	                  </Button>
143	                </Popover>
144	              ) : (
145	                t('Scheduling will not be possible at this state')
146	              )}
147	            </Alert>
148	          ) : (
149	            !loaded && !loadError && <Loading />
150	          )}
151	        </FormGroup>
152	      </Form>
153	    </TabModal>
154	  );
155	};
156	
157	export default DedicatedResourcesModal;

